INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00107', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '對於新入監受刑人，監獄應調查其應備文件後，予以收監，不得拒絕。但根據監獄行刑法施行細則第 9條規定，受刑人入監時，未攜帶何種文件，應拒絕收監？', '["指揮書", "裁判書", "人相表、身分單、性行報告表", "偵、審筆錄簽名、指紋、照片"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00108', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法之規定，有關受刑人假釋提報流程，下列敘述何者錯誤？', '["假釋審查應參酌受刑人之犯行情節、在監行狀、犯罪紀錄、教化矯治處遇成效、更生計畫及其他有 關事項，綜合判斷其悛悔情形", "受刑人得向監獄請求閱覽、抄錄、複製假釋審查相關資料。但所涉資料屬政府資訊公開法第18條 第1項或檔案法第18條所定情形者，不在此限", "監獄召開假釋審查會前，應以適當之方式給予受刑人陳述意見之機會", "經法務部不予許可假釋之處分案，除進級者外，監獄應逾三月始得再行陳報。但該受刑人嗣後獲 第84條第1項第5款至第7款所列之獎勵者，監獄得提前二個月陳報"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00109', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法第19條第1項規定，適用累進處遇之受刑人有下列情形之一者，監獄得給予和緩處遇？', '["患有疾病經醫師證明須短暫療養者", "懷胎六月以上，或生產未滿三月者", "衰老、身心障礙、行動不便或不能自理生活者", "有客觀事實足認其身心狀況欠缺辨識能力，但尚能處理自己事務者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00110', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '根據監獄施用戒具與施以固定保護及保護室收容管理辦法，監獄施以固定保護時，得以保護性之約束 工具拘束受刑人身體或四肢。下列何者並非保護性之約束工具？', '["安全帽", "四肢約束帶", "胸部約束帶", "約束手套"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00111', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法及其相關規定，監獄受刑人人數嚴重超額時或有其他特殊情形，必要時得機動調整移監， 下列敘述何者錯誤？', '["監督機關視各監獄收容之實際狀況，必要時得機動調整移監", "監獄依據受刑人調查分類之結果，認須加強教化", "受刑人對於其他受刑人有顯著之不良影響，有離開本監之必要", "受刑人移監作業由移入監獄負責。但有正當理由者，得報請監督機關決定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00112', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法及其相關法規規定，得運用科技設備輔助戒護，下列敘述何者錯誤？', '["科技設備種類有監控設備、檢查設備、採集設備、辨識設備等4種", "存放槍械或器械處所、機房進出口，得設置監控設備", "勤務中心、新收中心，得設置檢查設備", "機關監控設備所儲存之影音資料，應至少保存三十日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00113', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法第22條第1項第1款規定，受刑人有「危害監獄安全之虞」時得施以隔離保護；另根據 監獄及看守所施以隔離保護辦法第4條第1項有關「危害監獄安全之虞」規定，下列敘述何者錯誤？', '["有事實足認為其生命、身體、自由有受到危害之虞時", "對他人施以強暴或脅迫，有危害機關安全之虞", "有騷動或暴動之行為，或教唆、煽惑他人為騷動或暴動之行為", "有其他事實足認為其行為對機關安全有造成危害之虞"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00114', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄戒具之相關規定，下列敘述何者錯誤？', '["戒具以腳鐐、手銬、聯鎖、束繩及其他經法務部核定之戒具為限", "腳鐐量以二公斤為限，如有必要，得加至四公斤。少年受刑人以一公斤為限，如有必要，得加至三 公斤", "手銬重量不得超過半公斤", "施用戒具應注意不得遮蔽受刑人之視線"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00115', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法及相關法規之規定，監獄之日間外出制度，下列敘述何者錯誤？', '["經核准外出之受刑人，應於指定時間內回監，必要時得向指定處所報到", "受刑人應具無期徒刑執行逾十五年，或有期徒刑執行逾二分之一，且在監執行期間逾六個月以上之 資格者，得報請監督機關核准外出", "受刑人外出或於監獄外從事活動時，監獄得運用科技設備，施以電子監控措施", "外出受刑人有於監外留宿必要者，監獄得指定其留宿處所，並報監督機關核准"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00116', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄遇有重大特殊情形，包含天災、事變，為加強監獄安全戒備、防護監獄設施與保護受刑人安全， 得為必要之處置以為因應。但根據監獄行刑法之規定，下列那一應變處置之敘述錯誤？', '["得請求警察機關或其他相關機關協助", "得由戒護人員分任災害防救工作", "得將受刑人護送至相當處所", "不及護送至相當處所，得暫行釋放"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
